#include <stdio.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, k;
        scanf("%d %d", &n, &k);
        int a[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &a[i]);
        }
        qsort(a, n, sizeof(int), compare);

        double sum = 0;
        for (int i = k; i < n - k; i++) {
            sum += a[i];
        }

        double average = sum / (n - 2 * k);
        printf("%.6f\n", average);
    }
    return 0;
}

