function Simpstat(input) {
    const lines = input.trim().split('\n');
    const T = parseInt(lines[0]);

    let index = 1;
    for (let t = 0; t < T; t++) {
        const [N, K] = lines[index++].split(' ').map(Number);
        const measurements = lines[index++].split(' ').map(Number);

        measurements.sort((a, b) => a - b); // Sort measurements in ascending order

        // Calculate the sum of remaining measurements after removing K lowest and K highest values
        let sum = 0;
        for (let i = K; i < N - K; i++) {
            sum += measurements[i];
        }

        // Calculate the average of the remaining measurements
        const average = sum / (N - 2 * K);
        console.log(average.toFixed(6)); // Output the average value with 6 decimal places
    }
}

